/**
 * OFAC SDN screening gate (31 CFR §501.404).
 *
 * Scenario #11 of guides/use-cases.md: a transaction whose creditor
 * side has a sanctions screening with screening_score >= 95
 * (effective exact match against the OFAC SDN List) is blocked and
 * an OFAC blocked-property report is due within 10 days (§501.603).
 *
 * Reads `creditor_payment_account.compliance_screenings[].sanctions_matches[]`
 * — Watchman/OFAC hits are written to the per-screening sanctions_matches
 * child collection. Reading the child list (rather than screening_type +
 * match_count) lets sibling rules dispatch on their own match collections
 * — internal_blocklist_lastname (#41) reads blocklist_matches[], a future
 * PEP rule reads pep_matches[], etc. — without cross-talk.
 *
 * False-positive override: a screening whose `false_positive_qualifier`
 * is `manual_override` (an investigator cleared the hit) or
 * `auto_suppressed` (system-cleared, e.g. exact dedupe) is skipped
 * entirely. Marking a screening cleared is the recorded compliance act
 * that lets a future transaction with the same parties settle.
 *
 * The corpus exercises the high-confidence band only — graduated
 * bands (#11a-d) are a future extension.
 */
export const handler = async (input) => {
  const creditor = input.creditor_payment_account;
  if (!creditor) return { ledger_accounts: {} };

  const CLEARED = ['manual_override', 'auto_suppressed'];
  const screenings = creditor.compliance_screenings || [];
  const hit = screenings.some(function (s) {
    if (CLEARED.indexOf(s.false_positive_qualifier) >= 0) return false;
    const matches = s.sanctions_matches || [];
    return matches.length > 0;
  });
  if (!hit) return { ledger_accounts: {} };

  const las = creditor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'ofac_sdn_match',
      block_reason: 'ofac_sdn_match',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
